import java.util.Scanner;

public class SecureBufferOverflowFix {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");

        String input = scanner.nextLine(); // Use nextLine() to read the entire line

        // Using StringBuffer to dynamically create a string that can accommodate user input of any length
        StringBuffer buffer = new StringBuffer();
        buffer.append(input);

        System.out.println("Hello, " + buffer.toString());
    }
}

